const rows = $input.all().map(i => i.json).filter(r => r.channel);
const out = [];
for (const row of rows) {
  for (const m of ['total','processed','failed','pending','duplicates','skipped','dlq']) {
    out.push({ json: {
      channel: row.channel,
      metric_name: `messages_per_minute.${m}`,
      metric_value: Number(row[m] || 0),
      dimensions: JSON.stringify({ channel: row.channel })
    }});
  }
}
return out;
